sql:
SELECT e.first_name || ' ' || e.last_name AS full_name, e.job_title
FROM employees e
ORDER BY e.last_name;

SELECT employees.first_name, employees.last_name, employees.job_title, employment_history.department
FROM employees
JOIN employment_history ON employees.emp_id = employment_history.emp_id;

external_knowledge:
"currently holding" implies that the employment is ongoing, which corresponds to the condition where the end date is null;
a position is considered to be "top" if it has the highest number of employees;
the results are ordered in descending order, meaning the positions with the most employees are listed first.

sql:
SELECT DISTINCT(employees.first_name || ' ' || employees.last_name) AS full_name
FROM employees
JOIN payroll ON employees.emp_id = payroll.emp_id;

SELECT e.first_name || ' ' || e.last_name AS Name, e.job_title AS Job_Title
FROM employees e
INNER JOIN performance_reviews pr ON e.emp_id = pr.emp_id;

SELECT employees.first_name, employees.last_name, employees.job_title, states.state_name
FROM employees
JOIN states ON employees.state = states.state_name;
